import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser, getSession } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const body = await request.json();
    const { username, avatarEmoji } = body;

    if (!username || typeof username !== "string") {
      return NextResponse.json({ error: "Username is required" }, { status: 400 });
    }

    const trimmed = username.trim().toLowerCase();

    if (trimmed.length < 3 || trimmed.length > 20) {
      return NextResponse.json({ error: "Username must be 3-20 characters" }, { status: 400 });
    }

    if (!/^[a-z0-9_]+$/.test(trimmed)) {
      return NextResponse.json({ error: "Username can only contain letters, numbers, and underscores" }, { status: 400 });
    }

    const existing = await prisma.user.findUnique({ where: { username: trimmed } });
    if (existing && existing.id !== user.id) {
      return NextResponse.json({ error: "Username is already taken" }, { status: 409 });
    }

    const updated = await prisma.user.update({
      where: { id: user.id },
      data: {
        username: trimmed,
        avatarEmoji: avatarEmoji || null,
      },
    });

    return NextResponse.json({
      user: {
        id: updated.id,
        email: updated.email,
        username: updated.username,
        firstName: updated.firstName,
        lastName: updated.lastName,
        profileImageUrl: updated.profileImageUrl,
        avatarEmoji: updated.avatarEmoji,
      },
    });
  } catch (error: any) {
    console.error("Onboarding error:", error);
    return NextResponse.json({ error: "Failed to complete onboarding" }, { status: 500 });
  }
}

export async function GET() {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  return NextResponse.json({
    needsOnboarding: !user.username,
    user: {
      id: user.id,
      email: user.email,
      username: user.username,
      avatarEmoji: user.avatarEmoji,
    },
  });
}

src/components/map/map-layout.tsx.content:
"use client";

import {
  useRef,
  useCallback,
  useEffect,
  useState,
  type ReactNode,
  type ReactElement,
  cloneElement,
  isValidElement,
} from "react";
import type { SnapPoint } from "@/components/bottom-sheet";
import { PlaceMap, type PlaceMapHandle } from "@/components/place-map";
import { BottomSheet } from "@/components/bottom-sheet";
import { FloatingSearch } from "@/components/map/floating-search";
import { AppShell } from "@/components/layout";

interface Place {
  id: string;
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  lat: number;
  lng: number;
  primaryType: string | null;
  types: string[] | null;
  priceLevel: string | null;
  photoRefs: string[] | null;
}

interface SavedPlace {
  id: string;
  userId?: string | null;
  placeId: string;
  hasBeen: boolean;
  rating: number | null;
  emoji?: string | null;
  visitedAt?: string | null;
  createdAt?: string;
  place: Place;
  savedBy?: {
    id: string;
    username: string | null;
    firstName: string | null;
    lastName: string | null;
    profileImageUrl: string | null;
  } | null;
}

interface UserData {
  id: string;
  email: string | null;
  username: string | null;
  firstName: string | null;
  lastName: string | null;
  profileImageUrl: string | null;
}

export interface SidebarInjectedProps {
  selectedPlaceId: string | null;
  onPlaceSelect: (savedPlaceId: string) => void;
  placeRowRefs: React.MutableRefObject<Map<string, HTMLDivElement>>;
}

interface MapLayoutProps {
  user: UserData | null;
  places: SavedPlace[];
  children: ReactNode;
  selectedPlaceId: string | null;
  onPlaceSelect: (savedPlaceId: string) => void;
  showMapSettings?: boolean;
  showSearch?: boolean;
  sheetComponent?: ReactNode;
  showAvatars?: boolean;
  disableFitToPlaces?: boolean;
}

export function MapLayout({
  user,
  places,
  children,
  selectedPlaceId,
  onPlaceSelect,
  showMapSettings = true,
  showSearch = false,
  sheetComponent,
  showAvatars = false,
  disableFitToPlaces = false,
}: MapLayoutProps) {
  const placeRowRefs = useRef<Map<string, HTMLDivElement>>(new Map());
  const mapRef = useRef<PlaceMapHandle>(null);
  const [sheetSnapRequest, setSheetSnapRequest] = useState<SnapPoint | null>(null);

  const snapTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const triggerSnapRequest = useCallback((point: SnapPoint) => {
    if (snapTimerRef.current) clearTimeout(snapTimerRef.current);
    setSheetSnapRequest(point);
    snapTimerRef.current = setTimeout(() => setSheetSnapRequest(null), 500);
  }, []);

  useEffect(() => {
    return () => {
      if (snapTimerRef.current) clearTimeout(snapTimerRef.current);
    };
  }, []);

  const handleMarkerClick = useCallback((savedPlaceId: string) => {
    onPlaceSelect(savedPlaceId);
    triggerSnapRequest("mid");
    const selectedPlace = places.find(p => p.id === savedPlaceId);
    if (selectedPlace && mapRef.current) {
      mapRef.current.panTo(selectedPlace.place.lat, selectedPlace.place.lng);
    }
    const rowElement = placeRowRefs.current.get(savedPlaceId);
    if (rowElement) {
      rowElement.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  }, [onPlaceSelect, triggerSnapRequest, places]);

  const handleSidebarPlaceSelect = useCallback((savedPlaceId: string) => {
    onPlaceSelect(savedPlaceId);
    triggerSnapRequest("mid");
    const selectedPlace = places.find(p => p.id === savedPlaceId);
    if (selectedPlace && mapRef.current) {
      mapRef.current.panTo(selectedPlace.place.lat, selectedPlace.place.lng);
    }
  }, [places, onPlaceSelect, triggerSnapRequest]);

  useEffect(() => {
    if (selectedPlaceId) {
      const selectedPlace = places.find(p => p.id === selectedPlaceId);
      if (selectedPlace && mapRef.current) {
        mapRef.current.panTo(selectedPlace.place.lat, selectedPlace.place.lng);
      }
    }
  }, [selectedPlaceId, places]);

  const injectedProps: SidebarInjectedProps = {
    selectedPlaceId,
    onPlaceSelect: handleSidebarPlaceSelect,
    placeRowRefs,
  };

  const renderChildrenWithProps = (children: ReactNode): ReactNode => {
    if (isValidElement(children)) {
      return cloneElement(children as ReactElement<SidebarInjectedProps>, injectedProps);
    }
    return children;
  };

  return (
    <AppShell user={user}>
      <div className="relative flex-1 overflow-hidden">
        <PlaceMap
          ref={mapRef}
          places={places}
          selectedPlaceId={selectedPlaceId}
          onMarkerClick={handleMarkerClick}
          showSettings={showMapSettings}
          showAvatars={showAvatars}
          disableFitToPlaces={disableFitToPlaces}
        />

        {showSearch && (
          <div className="absolute top-3 left-3 right-3 md:left-[26.5rem] z-[55]">
            <FloatingSearch />
          </div>
        )}

        <div className="absolute top-0 left-0 bottom-0 z-10 w-[25rem] p-3 hidden md:block">
          <div className="h-full bg-background rounded-lg border shadow-lg overflow-hidden">
            {renderChildrenWithProps(children)}
          </div>
        </div>

        <div className="md:hidden">
          <BottomSheet defaultSnapPoint="mid" requestedSnapPoint={sheetSnapRequest}>
            {renderChildrenWithProps(children)}
          </BottomSheet>
        </div>
      </div>

      {sheetComponent}
    </AppShell>
  );
}

src/components/map/floating-search.tsx.content:
"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { HugeiconsIcon } from "@hugeicons/react";
import {
  Search01Icon,
  Bookmark01Icon,
  Cancel01Icon,
} from "@hugeicons/core-free-icons";
import { SaveToListDropdown } from "@/components/shared/save-to-list-dropdown";
import type { SaveToListDropdownHandle } from "@/components/shared/save-to-list-dropdown";

interface PlacePrediction {
  place_id: string;
  description: string;
  structured_formatting: {
    main_text: string;
    secondary_text: string;
  };
}

const EMPTY_PLACE = {
  googlePlaceId: "",
  name: "",
  formattedAddress: "",
  lat: 0,
  lng: 0,
};

export function FloatingSearch() {
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<PlacePrediction[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isFocused, setIsFocused] = useState(false);
  const [activePrediction, setActivePrediction] = useState<PlacePrediction | null>(null);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const locationRequested = useRef(false);
  const saveRef = useRef<SaveToListDropdownHandle>(null);

  const currentPlace = activePrediction ? {
    googlePlaceId: activePrediction.place_id,
    name: activePrediction.structured_formatting.main_text,
    formattedAddress: activePrediction.structured_formatting.secondary_text,
    lat: 0,
    lng: 0,
  } : EMPTY_PLACE;

  useEffect(() => {
    if (!locationRequested.current && navigator.geolocation) {
      locationRequested.current = true;
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        () => {},
        { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 }
      );
    }
  }, []);

  const searchPlaces = useCallback(async (query: string) => {
    if (!query.trim()) {
      setSearchResults([]);
      return;
    }
    setIsSearching(true);
    try {
      let url = `/api/places/search?q=${encodeURIComponent(query)}`;
      if (userLocation) {
        url += `&lat=${userLocation.lat}&lng=${userLocation.lng}`;
      }
      const response = await fetch(url);
      const data = await response.json();
      setSearchResults(data.predictions || []);
    } catch (error) {
      console.error("Search error:", error);
    } finally {
      setIsSearching(false);
    }
  }, [userLocation]);

  useEffect(() => {
    const debounce = setTimeout(() => searchPlaces(searchQuery), 300);
    return () => clearTimeout(debounce);
  }, [searchQuery, searchPlaces]);

  const handleClear = () => {
    setSearchQuery("");
    setSearchResults([]);
    setActivePrediction(null);
  };

  const handleSaveClick = (prediction: PlacePrediction) => {
    const placeToSave = {
      googlePlaceId: prediction.place_id,
      name: prediction.structured_formatting.main_text,
      formattedAddress: prediction.structured_formatting.secondary_text,
      lat: 0,
      lng: 0,
    };
    pendingSaveRef.current = placeToSave;
    handleClear();
    setTimeout(() => {
      saveRef.current?.triggerSave();
    }, 50);
  };

  const pendingSaveRef = useRef<typeof currentPlace | null>(null);
  const activePlace = pendingSaveRef.current || currentPlace;

  const showResults = isFocused && (isSearching || searchResults.length > 0 || searchQuery.trim().length > 0);

  return (
    <div className="md:w-96 md:ml-auto">
      <div className="relative">
        <HugeiconsIcon icon={Search01Icon} className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <Input
          placeholder="Search for a place..."
          value={searchQuery}
          onChange={(e) => {
            setSearchQuery(e.target.value);
          }}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setTimeout(() => setIsFocused(false), 300)}
          className="pl-10 pr-8 bg-background dark:bg-background shadow-lg border"
          data-testid="input-search-place"
        />
        {searchQuery && (
          <button
            onClick={handleClear}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
            data-testid="button-clear-search"
          >
            <HugeiconsIcon icon={Cancel01Icon} className="h-4 w-4" />
          </button>
        )}
      </div>

      {showResults && (
        <div className="mt-2 bg-background border rounded-lg shadow-lg max-h-96 overflow-y-auto">
          {isSearching && (
            <div className="space-y-2 p-3">
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-12 w-full" />
            </div>
          )}
          {!isSearching && searchResults.length > 0 && (
            <div className="py-1">
              {searchResults.map((result) => (
                <button
                  key={result.place_id}
                  className="flex items-center gap-2 px-3 py-2 hover-elevate w-full text-left"
                  onClick={() => handleSaveClick(result)}
                  data-testid={`search-result-${result.place_id}`}
                >
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-sm truncate">{result.structured_formatting.main_text}</p>
                    <p className="text-xs text-muted-foreground truncate">{result.structured_formatting.secondary_text}</p>
                  </div>
                  <div className="flex items-center flex-shrink-0">
                    <HugeiconsIcon icon={Bookmark01Icon} className="h-4 w-4 text-muted-foreground" />
                  </div>
                </button>
              ))}
            </div>
          )}
          {!isSearching && searchQuery && searchResults.length === 0 && (
            <p className="p-3 text-center text-sm text-muted-foreground">No places found</p>
          )}
        </div>
      )}

      <div className="hidden">
        <SaveToListDropdown
          ref={saveRef}
          place={activePlace}
          onSaveSuccess={() => { pendingSaveRef.current = null; }}
        />
      </div>
    </div>
  );
}

