src/components/place-map.tsx.content:
"use client";

import { useEffect, useRef, useCallback, useImperativeHandle, forwardRef, useMemo } from "react";
import { Map, MapMarker, MarkerContent, useMap, type MapRef } from "@/components/ui/map";
import { MapControls } from "@/components/map/map-controls";
import { cn } from "@/lib/utils";
import {
  getStoredMapStyle,
  applyMapStyle,
  applyLabelDensity,
  getStoredLabelDensity,
  type MapStyleKey,
  type LabelDensity,
} from "@/lib/map-styles";

interface Place {
  id: string;
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  lat: number;
  lng: number;
}

interface SavedPlace {
  id: string;
  emoji?: string | null;
  place: Place;
  savedBy?: {
    id: string;
    username: string | null;
    firstName: string | null;
    lastName: string | null;
    profileImageUrl: string | null;
  } | null;
}

interface PlaceMapProps {
  places: SavedPlace[];
  selectedPlaceId: string | null;
  onMarkerClick: (savedPlaceId: string) => void;
  showSettings?: boolean;
  isSettingsOpen?: boolean;
  onSettingsOpenChange?: (open: boolean) => void;
  showAvatars?: boolean;
  disableFitToPlaces?: boolean;
}

export interface PlaceMapHandle {
  panTo: (lat: number, lng: number) => void;
  setZoom: (zoom: number) => void;
}

const MARKER_COLOR = "#0004EC";
const DEFAULT_CENTER: [number, number] = [-74.006, 40.7128];
const DEFAULT_ZOOM = 12;

const MAP_STORAGE_KEY = "twnsq-map-view";

function getStoredMapView(): { center: [number, number]; zoom: number } | null {
  if (typeof window === "undefined") return null;
  try {
    const stored = localStorage.getItem(MAP_STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored);
      if (parsed.center && typeof parsed.zoom === "number") {
        return { center: [parsed.center.lng ?? parsed.center[0], parsed.center.lat ?? parsed.center[1]], zoom: parsed.zoom };
      }
    }
  } catch (e) {}
  return null;
}

function saveMapView(center: [number, number], zoom: number) {
  if (typeof window === "undefined") return;
  try {
    localStorage.setItem(MAP_STORAGE_KEY, JSON.stringify({ center, zoom }));
  } catch (e) {}
}

function BoundsController({ places, disableFitToPlaces }: { places: SavedPlace[]; disableFitToPlaces?: boolean }) {
  const { map, isLoaded } = useMap();
  const hasInitializedRef = useRef(false);
  const prevPlaceSignatureRef = useRef<string>("");

  const getPlaceSignature = useCallback((placeList: SavedPlace[]) => {
    return placeList.map(p => `${p.id}:${p.place.lat},${p.place.lng}`).sort().join("|");
  }, []);

  const fitToPlaces = useCallback((m: google.maps.Map, placeList: SavedPlace[]) => {
    if (placeList.length === 0) return;
    if (placeList.length === 1) {
      m.panTo({ lat: placeList[0].place.lat, lng: placeList[0].place.lng });
      m.setZoom(14);
    } else {
      const bounds = new google.maps.LatLngBounds();
      placeList.forEach((sp) => {
        bounds.extend({ lat: sp.place.lat, lng: sp.place.lng });
      });
      m.fitBounds(bounds, { top: 60, right: 60, bottom: 220, left: 60 });
    }
  }, []);

  useEffect(() => {
    if (!map || !isLoaded || hasInitializedRef.current) return;
    hasInitializedRef.current = true;
    prevPlaceSignatureRef.current = getPlaceSignature(places);

    if (disableFitToPlaces) {
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(
          (position) => {
            map.panTo({ lat: position.coords.latitude, lng: position.coords.longitude });
            map.setZoom(12);
          },
          () => {},
          { enableHighAccuracy: true, timeout: 5000 }
        );
      }
      return;
    }

    const storedView = getStoredMapView();
    if (storedView) return;

    if (!("geolocation" in navigator)) {
      fitToPlaces(map, places);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        map.panTo({ lat: latitude, lng: longitude });
        map.setZoom(12);
      },
      () => fitToPlaces(map, places),
      { enableHighAccuracy: true, timeout: 5000 }
    );
  }, [map, isLoaded, places, getPlaceSignature, fitToPlaces, disableFitToPlaces]);

  useEffect(() => {
    if (disableFitToPlaces) return;
    if (!map || !isLoaded || !hasInitializedRef.current) return;
    const newSig = getPlaceSignature(places);
    if (newSig !== prevPlaceSignatureRef.current && places.length > 0) {
      prevPlaceSignatureRef.current = newSig;
      fitToPlaces(map, places);
    }
  }, [map, isLoaded, places, getPlaceSignature, fitToPlaces, disableFitToPlaces]);

  useEffect(() => {
    if (!map || !isLoaded) return;
    const listener = map.addListener("idle", () => {
      const center = map.getCenter();
      if (center) {
        saveMapView([center.lng(), center.lat()], map.getZoom() || DEFAULT_ZOOM);
      }
    });
    return () => { google.maps.event.removeListener(listener); };
  }, [map, isLoaded]);

  return null;
}

function StyleController() {
  const { map, isLoaded } = useMap();

  useEffect(() => {
    if (!map || !isLoaded) return;

    const handleStyleChange = (e: Event) => {
      const styleKey = (e as CustomEvent).detail as MapStyleKey;
      const density = getStoredLabelDensity();
      applyMapStyle(map, styleKey);
      applyLabelDensity(map, density, styleKey);
    };

    const handleLabelDensityChange = (e: Event) => {
      const density = (e as CustomEvent).detail as LabelDensity;
      const styleKey = getStoredMapStyle();
      applyLabelDensity(map, density, styleKey);
    };

    const initialStyleKey = getStoredMapStyle();
    const initialDensity = getStoredLabelDensity();
    applyMapStyle(map, initialStyleKey);
    applyLabelDensity(map, initialDensity, initialStyleKey);

    window.addEventListener("map-style-change", handleStyleChange);
    window.addEventListener("map-label-density-change", handleLabelDensityChange);

    return () => {
      window.removeEventListener("map-style-change", handleStyleChange);
      window.removeEventListener("map-label-density-change", handleLabelDensityChange);
    };
  }, [map, isLoaded]);

  return null;
}

export const PlaceMap = forwardRef<PlaceMapHandle, PlaceMapProps>(function PlaceMap(
  { places, selectedPlaceId, onMarkerClick, showAvatars = false, disableFitToPlaces = false },
  ref
) {
  const mapRef = useRef<MapRef>(null);

  useImperativeHandle(ref, () => ({
    panTo: (lat: number, lng: number) => {
      const m = mapRef.current;
      if (!m) return;
      m.panTo({ lat, lng });
      const currentZoom = m.getZoom() || 12;
      if (currentZoom < 14) m.setZoom(14);
    },
    setZoom: (zoom: number) => {
      mapRef.current?.setZoom(zoom);
    },
  }));

  const storedView = useMemo(() => getStoredMapView(), []);
  const initialCenter = storedView?.center || DEFAULT_CENTER;
  const initialZoom = storedView?.zoom || DEFAULT_ZOOM;

  const onMarkerClickRef = useRef(onMarkerClick);
  onMarkerClickRef.current = onMarkerClick;

  return (
    <div className="relative h-full w-full" data-testid="map-container">
      <Map
        ref={mapRef}
        center={initialCenter}
        zoom={initialZoom}
        className="h-full w-full"
      >
        <BoundsController places={places} disableFitToPlaces={disableFitToPlaces} />
        <StyleController />
        <MapControls places={places} />
        {places.map((savedPlace) => (
          <PlaceMarker
            key={savedPlace.id}
            savedPlace={savedPlace}
            isSelected={savedPlace.id === selectedPlaceId}
            onClickRef={onMarkerClickRef}
            showAvatar={showAvatars}
          />
        ))}
      </Map>
    </div>
  );
});

function PlaceMarker({
  savedPlace,
  isSelected,
  onClickRef,
  showAvatar = false,
}: {
  savedPlace: SavedPlace;
  isSelected: boolean;
  onClickRef: React.MutableRefObject<(id: string) => void>;
  showAvatar?: boolean;
}) {
  const handleClick = useCallback(
    (e: MouseEvent) => {
      e.stopPropagation();
      onClickRef.current(savedPlace.id);
    },
    [savedPlace.id, onClickRef]
  );

  const emoji = savedPlace.emoji;
  const avatarUrl = showAvatar ? savedPlace.savedBy?.profileImageUrl : null;

  return (
    <MapMarker
      longitude={savedPlace.place.lng}
      latitude={savedPlace.place.lat}
      onClick={handleClick}
    >
      <MarkerContent>
        {avatarUrl ? (
          <div
            className={cn(
              "rounded-full shadow-md transition-all duration-200 overflow-hidden hover:scale-110",
              isSelected ? "w-9 h-9 scale-110" : "w-7 h-7",
            )}
            style={{
              borderWidth: "2.5px",
              borderStyle: "solid",
              borderColor: "white",
            }}
            data-testid={`marker-${savedPlace.id}`}
          >
            <img
              src={avatarUrl}
              alt=""
              className="w-full h-full object-cover"
              referrerPolicy="no-referrer"
            />
          </div>
        ) : (
          <div
            className={cn(
              "flex items-center justify-center transition-all duration-200",
              emoji
                ? "text-2xl drop-shadow-md hover:scale-110"
                : "rounded-full shadow-md hover:scale-125",
              isSelected && emoji && "scale-125 drop-shadow-lg",
              isSelected && !emoji && "scale-150 shadow-lg",
            )}
            style={!emoji ? {
              width: "14px",
              height: "14px",
              backgroundColor: MARKER_COLOR,
              borderWidth: "2.5px",
              borderStyle: "solid",
              borderColor: "white",
            } : undefined}
            data-testid={`marker-${savedPlace.id}`}
          >
            {emoji || null}
          </div>
        )}
      </MarkerContent>
    </MapMarker>
  );
}

src/app/api/chat/save-all-to-list/route..content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { createActivity } from "@/lib/activity";
import { getDefaultEmoji } from "@/lib/default-emoji";
import { autoTagPlace } from "@/lib/auto-tag-place";
import { autoSummaryPlace } from "@/lib/auto-summary-place";

interface PlaceData {
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  lat: number;
  lng: number;
  types: string[];
  primaryType: string | null;
  priceLevel: string | null;
  rating: number | null;
  userRatingsTotal: number | null;
  photoRef: string | null;
  emoji: string | null;
}

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const body = await request.json();
    const { listName, listId, places } = body as { listName?: string; listId?: string; places: PlaceData[] };

    if (!places || places.length === 0) {
      return NextResponse.json({ error: "At least one place is required" }, { status: 400 });
    }

    let list;
    if (listId) {
      list = await prisma.list.findFirst({
        where: { id: listId, userId: user.id },
      });
      if (!list) {
        return NextResponse.json({ error: "List not found" }, { status: 404 });
      }
    } else {
      const autoName = listName?.trim() || `Saved Places (${new Date().toLocaleDateString("en-US", { month: "short", day: "numeric" })})`;
      list = await prisma.list.create({
        data: {
          userId: user.id,
          name: autoName,
          visibility: "PRIVATE",
        },
      });
    }

    let savedCount = 0;

    for (const placeData of places) {
      let place = await prisma.place.upsert({
        where: { googlePlaceId: placeData.googlePlaceId },
        create: {
          googlePlaceId: placeData.googlePlaceId,
          name: placeData.name,
          formattedAddress: placeData.formattedAddress,
          lat: placeData.lat,
          lng: placeData.lng,
          types: placeData.types || [],
          primaryType: placeData.primaryType,
          priceLevel: placeData.priceLevel ?? null,
          photoRefs: placeData.photoRef ? [placeData.photoRef] : [],
        },
        update: {
          name: placeData.name,
          formattedAddress: placeData.formattedAddress,
          types: placeData.types ?? undefined,
          primaryType: placeData.primaryType ?? undefined,
          priceLevel: placeData.priceLevel ?? undefined,
          photoRefs: placeData.photoRef ? [placeData.photoRef] : undefined,
        },
      });

      let savedPlace = await prisma.savedPlace.findUnique({
        where: {
          userId_placeId: {
            userId: user.id,
            placeId: place.id,
          },
        },
      });

      if (!savedPlace) {
        const emoji = placeData.emoji || getDefaultEmoji(placeData.primaryType, placeData.types);
        savedPlace = await prisma.savedPlace.create({
          data: {
            userId: user.id,
            placeId: place.id,
            hasBeen: false,
            emoji,
          },
        });
      } else if (!savedPlace.emoji) {
        const fallbackEmoji = placeData.emoji || getDefaultEmoji(placeData.primaryType, placeData.types);
        await prisma.savedPlace.update({
          where: { id: savedPlace.id },
          data: { emoji: fallbackEmoji },
        });
      }

      const existingListPlace = await prisma.listPlace.findUnique({
        where: {
          listId_placeId: {
            listId: list.id,
            placeId: place.id,
          },
        },
      });

      if (!existingListPlace) {
        await prisma.listPlace.create({
          data: {
            listId: list.id,
            placeId: place.id,
          },
        });
        savedCount++;
      }

      autoTagPlace(place.id).catch(() => {});
      autoSummaryPlace(place.id).catch(() => {});
    }

    if (!listId) {
      await createActivity({
        actorId: user.id,
        type: "LIST_CREATED",
        listId: list.id,
        metadata: { listName: list.name, placeCount: savedCount },
      });
    }

    return NextResponse.json({ 
      list: { id: list.id, name: list.name },
      savedCount,
    });
  } catch (error: any) {
    console.error("Save all to list error:", error);
    return NextResponse.json({ error: "Failed to save places to list" }, { status: 500 });
  }
}

src/app/api/admin/import/jobs/[id]/posts.content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await getCurrentUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { id } = await params;
    const { searchParams } = new URL(request.url);
    const status = searchParams.get("status") || undefined;

    const posts = await prisma.ingestedPost.findMany({
      where: {
        importJobId: id,
        ...(status ? { status: status as any } : {}),
      },
      orderBy: { createdAt: "desc" },
      take: 200,
    });

    return NextResponse.json({ posts });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

