src/lib/activity.ts.content:
import { prisma } from "@/lib/prisma";
import { activity_type, Prisma } from "@/generated/prisma";

interface ActivityData {
  actorId: string;
  type: activity_type;
  placeId?: string;
  listId?: string;
  metadata?: Prisma.InputJsonValue;
}

function generateDedupeKey(data: ActivityData): string {
  const date = new Date().toISOString().split("T")[0];
  const targetId = data.placeId || data.listId || "none";
  return `${data.actorId}:${data.type}:${targetId}:${date}`;
}

export async function createActivity(data: ActivityData): Promise<void> {
  const dedupeKey = generateDedupeKey(data);

  try {
    await prisma.activity.create({
      data: {
        actorId: data.actorId,
        type: data.type,
        placeId: data.placeId || null,
        listId: data.listId || null,
        metadata: data.metadata,
        dedupeKey,
      },
    });
  } catch (error: any) {
    if (error.code === "P2002") {
      return;
    }
    throw error;
  }
}

src/components/place-photo-grid.tsx.content:
"use client";

import { useState } from "react";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { HugeiconsIcon } from "@hugeicons/react";
import { ArrowLeft01Icon, ArrowRight01Icon, Cancel01Icon, Image01Icon } from "@hugeicons/core-free-icons";
import { VisuallyHidden } from "@radix-ui/react-visually-hidden";

interface Photo {
  id: string;
  url: string;
  width?: number | null;
  height?: number | null;
}

interface PlacePhotoGridProps {
  photos: Photo[];
  maxDisplay?: number;
}

export function PlacePhotoGrid({ photos, maxDisplay = 5 }: PlacePhotoGridProps) {
  const [selectedIndex, setSelectedIndex] = useState<number | null>(null);

  if (photos.length === 0) {
    return (
      <div 
        className="flex items-center justify-center bg-muted rounded-lg h-48"
        data-testid="photo-grid-empty"
      >
        <div className="text-center text-muted-foreground">
          <HugeiconsIcon icon={Image01Icon} className="mx-auto h-8 w-8 mb-2" />
          <p className="text-sm">No photos available</p>
        </div>
      </div>
    );
  }

  const displayPhotos = photos.slice(0, maxDisplay);
  const remainingCount = photos.length - maxDisplay;

  const openLightbox = (index: number) => setSelectedIndex(index);
  const closeLightbox = () => setSelectedIndex(null);
  const goToPrevious = () => {
    if (selectedIndex !== null) {
      setSelectedIndex((selectedIndex - 1 + photos.length) % photos.length);
    }
  };
  const goToNext = () => {
    if (selectedIndex !== null) {
      setSelectedIndex((selectedIndex + 1) % photos.length);
    }
  };

  return (
    <>
      <div className="grid grid-cols-4 grid-rows-2 gap-1 h-64 rounded-lg" data-testid="photo-grid">
        {displayPhotos.length >= 1 && (
          <button
            type="button"
            className="col-span-2 row-span-2 relative overflow-hidden rounded-l-lg"
            onClick={() => openLightbox(0)}
            data-testid="photo-grid-main"
          >
            <img
              src={displayPhotos[0].url}
              alt="Main photo"
              className="h-full w-full object-cover"
            />
          </button>
        )}
        {displayPhotos.slice(1, 5).map((photo, index) => (
          <button
            key={photo.id}
            type="button"
            className="relative overflow-hidden"
            onClick={() => openLightbox(index + 1)}
            data-testid={`photo-grid-${index + 1}`}
          >
            <img
              src={photo.url}
              alt={`Photo ${index + 2}`}
              className="h-full w-full object-cover"
            />
            {index === 3 && remainingCount > 0 && (
              <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                <span className="text-white text-sm font-medium">
                  +{remainingCount} more
                </span>
              </div>
            )}
          </button>
        ))}
        {displayPhotos.length === 1 && (
          <>
            <div className="col-span-2 row-span-2 bg-muted" />
          </>
        )}
        {displayPhotos.length === 2 && (
          <>
            <div className="bg-muted" />
            <div className="bg-muted" />
            <div className="bg-muted" />
          </>
        )}
        {displayPhotos.length === 3 && (
          <>
            <div className="bg-muted" />
            <div className="bg-muted" />
          </>
        )}
        {displayPhotos.length === 4 && (
