src/components/sidebars/user-sidebar.tsx.content:
"use client";

import { useState, useMemo } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import { SidebarTrigger } from "@/components/ui/sidebar";
import { HugeiconsIcon } from "@hugeicons/react";
import { UserAdd01Icon, UserRemove01Icon, Loading03Icon, ArrowDown01Icon, Tick01Icon, Activity01Icon } from "@hugeicons/core-free-icons";
import { apiRequest } from "@/lib/query-client";
import { toast } from "sonner";
import { PlacesList } from "@/components/shared/places-list";
import { FeedPost } from "@/components/feed-post";
import type { SidebarInjectedProps } from "@/components/map/map-layout";

interface Place {
  id: string;
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  neighborhood?: string | null;
  locality?: string | null;
  lat: number;
  lng: number;
  primaryType: string | null;
  types: string[] | null;
  priceLevel: string | null;
  photoRefs: string[] | null;
}

interface SavedPlace {
  id: string;
  placeId: string;
  hasBeen: boolean;
  rating: number | null;
  createdAt: string;
  place: Place;
}

interface ListData {
  id: string;
  name: string;
  visibility: "PRIVATE" | "PUBLIC";
  listPlaces: Array<{ placeId: string }>;
  _count: { listPlaces: number };
}

interface UserData {
  id: string;
  email: string | null;
  username: string | null;
  firstName: string | null;
  lastName: string | null;
  profileImageUrl: string | null;
}

interface ActivityData {
  id: string;
  actorId: string;
  type: "PLACE_SAVED" | "PLACE_MARKED_BEEN" | "PLACE_ADDED_TO_LIST" | "LIST_CREATED" | "REVIEW_CREATED";
  placeId: string | null;
  listId: string | null;
  metadata: { placeName?: string; listName?: string; rating?: number; note?: string; review_preview?: string } | null;
  createdAt: string;
  actor: {
    id: string;
    username: string | null;
    firstName: string | null;
    lastName: string | null;
    profileImageUrl: string | null;
  };
  place: {
    id: string;
    googlePlaceId: string;
    name: string;
    formattedAddress: string;
    photoRefs?: string[] | null;
  } | null;
  list: {
    id: string;
    name: string;
    visibility: string;
    userId: string | null;
  } | null;
}

interface CurrentUserPlaceData {
  savedPlaceId: string | null;
  hasBeen: boolean;
  rating: number | null;
  lists: Array<{ id: string; name: string }>;
}

interface UserSidebarProps extends Partial<SidebarInjectedProps> {
  user: UserData;
  isOwnProfile: boolean;
  isFollowing: boolean;
  followerCount: number;
  followingCount: number;
  places: SavedPlace[];
  lists: ListData[];
  activities: ActivityData[];
  isLoading?: boolean;
  currentUserPlaceData?: Record<string, CurrentUserPlaceData> | null;
}

const statusOptions = [
  { value: "all", label: "All" },
  { value: "not_visited", label: "Not visited" },
  { value: "been", label: "Been" },
];

function ProfileHeader({
  user,
  followerCount,
  followingCount,
}: {
  user: UserData;
  followerCount: number;
  followingCount: number;
}) {
  const displayName = user.firstName 
    ? `${user.firstName}${user.lastName ? ` ${user.lastName}` : ""}`
    : user.username || "User";

  const handle = user.username || user.id;

  return (
    <div className="flex items-center gap-3 p-3 border-b">
      <Avatar className="h-14 w-14 border-2 border-border shrink-0">
        <AvatarImage src={user.profileImageUrl || undefined} alt={displayName} />
        <AvatarFallback className="text-lg font-medium">{displayName.charAt(0).toUpperCase()}</AvatarFallback>
      </Avatar>

      <div className="flex-1 min-w-0">
        <h2 className="text-sm font-semibold truncate font-brand" data-testid="text-profile-name">{displayName}</h2>
        <p className="text-xs text-muted-foreground" data-testid="text-profile-username">@{handle}</p>

        <div className="flex items-center gap-4 mt-1 text-xs">
          <button className="hover:underline" data-testid="text-following">
            <span className="font-semibold">{followingCount}</span>
            <span className="text-muted-foreground ml-1">following</span>
          </button>
          <button className="hover:underline" data-testid="text-followers">
            <span className="font-semibold">{followerCount}</span>
            <span className="text-muted-foreground ml-1">{followerCount === 1 ? "follower" : "followers"}</span>
          </button>
        </div>
      </div>
    </div>
  );
}

export function UserSidebar({
  user,
  isOwnProfile,
  isFollowing,
  followerCount,
  followingCount,
  places,
  lists,
  activities,
  isLoading = false,
  selectedPlaceId,
  onPlaceSelect,
  placeRowRefs,
  currentUserPlaceData,
}: UserSidebarProps) {
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState<"places" | "feed">("places");
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<string>("all");
  const [selectedListId, setSelectedListId] = useState<string>("all");
  const [localIsFollowing, setLocalIsFollowing] = useState(isFollowing);
  const [localFollowerCount, setLocalFollowerCount] = useState(followerCount);

  const resolvedCurrentUserPlaceData = useMemo(() => {
    if (currentUserPlaceData) return currentUserPlaceData;
    if (!isOwnProfile) return null;
    const map: Record<string, CurrentUserPlaceData> = {};
    for (const sp of places) {
      map[sp.placeId] = {
        savedPlaceId: sp.id,
        hasBeen: sp.hasBeen,
        rating: sp.rating,
        lists: [],
      };
    }
    return map;
  }, [currentUserPlaceData, isOwnProfile, places]);

  const followMutation = useMutation({
    mutationFn: async (userId: string) => {
      return apiRequest("/api/follows", {
        method: "POST",
        body: JSON.stringify({ followingId: userId }),
      });
    },
    onSuccess: () => {
      const wasFollowing = localIsFollowing;
      setLocalIsFollowing(!wasFollowing);
      setLocalFollowerCount(prev => wasFollowing ? prev - 1 : prev + 1);
      queryClient.invalidateQueries({ queryKey: ["user-profile", user.username] });
      toast.success(wasFollowing ? "Unfollowed" : "Following");
    },
    onError: (error: Error) => toast.error(error.message || "Failed to update follow status"),
  });

  const handleFollow = () => {
    followMutation.mutate(user.id);
  };

  const selectedList = lists.find(l => l.id === selectedListId);
  const selectedListPlaceIds = selectedList?.listPlaces?.map(lp => lp.placeId) || [];

  const filteredPlaces = places.filter((sp) => {
    if (selectedListId !== "all" && !selectedListPlaceIds.includes(sp.placeId)) {
      return false;
    }
    if (selectedStatusFilter === "not_visited") return !sp.hasBeen;
    if (selectedStatusFilter === "been") return sp.hasBeen;
    return true;
  });

  const selectedStatusLabel = statusOptions.find((o) => o.value === selectedStatusFilter)?.label || "All";
  const selectedListLabel = selectedListId === "all" 
    ? "All Lists" 
    : lists.find((l) => l.id === selectedListId)?.name || "All Lists";

  const publicLists = lists.filter(l => l.visibility === "PUBLIC" || isOwnProfile);

  const combinedFilterValue = selectedListId !== "all" ? `list:${selectedListId}` : selectedStatusFilter;
  const combinedFilterLabel = selectedListId !== "all"
    ? (lists.find(l => l.id === selectedListId)?.name || "All")
    : selectedStatusFilter === "been" ? "Places they've been" : selectedStatusLabel;

  const displayName = user.firstName 
    ? `${user.firstName}${user.lastName ? ` ${user.lastName}` : ""}`
    : user.username || "User";

  if (isLoading) {
    return (
      <div className="h-full flex flex-col bg-background">
        <div className="flex items-center gap-2 p-3 border-b">
          <SidebarTrigger data-testid="button-sidebar-toggle" />
          <Skeleton className="h-4 w-24 flex-1" />
        </div>
        <div className="flex items-center gap-3 p-3 border-b">
          <Skeleton className="h-14 w-14 rounded-full shrink-0" />
          <div className="flex-1 space-y-2">
            <Skeleton className="h-4 w-32" />
            <Skeleton className="h-3 w-24" />
            <div className="flex gap-4">
              <Skeleton className="h-3 w-16" />
              <Skeleton className="h-3 w-16" />
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-background" data-testid="user-sidebar">
      <div className="flex items-center gap-2 p-3 border-b shrink-0">
        <SidebarTrigger className="hidden md:flex" data-testid="button-sidebar-toggle" />
        <span className="font-semibold text-sm flex-1 truncate font-brand">{displayName}</span>
        {!isOwnProfile && (
          <Button
            variant={localIsFollowing ? "outline" : "default"}
            size="sm"
            onClick={handleFollow}
            disabled={followMutation.isPending}
            data-testid="button-follow"
          >
            {followMutation.isPending ? (
              <HugeiconsIcon icon={Loading03Icon} className="h-4 w-4 animate-spin" />
            ) : localIsFollowing ? (
              <><HugeiconsIcon icon={UserRemove01Icon} className="mr-1.5 h-4 w-4" />Following</>
            ) : (
              <><HugeiconsIcon icon={UserAdd01Icon} className="mr-1.5 h-4 w-4" />Follow</>
            )}
          </Button>
        )}
      </div>

      <div className="flex-1 overflow-y-auto">
        <ProfileHeader
          user={user}
          followerCount={localFollowerCount}
          followingCount={followingCount}
        />

        <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as "places" | "feed")} className="flex flex-col gap-0">
          <div className="flex items-center justify-between gap-2 px-3 py-2 border-b sticky top-0 bg-background z-10">
          <TabsList className="justify-start">
            <TabsTrigger 
              value="places" 
              data-testid="tab-places"
            >
              Places
            </TabsTrigger>
            <TabsTrigger 
              value="feed" 
              data-testid="tab-feed"
            >
              Feed
            </TabsTrigger>
          </TabsList>

          {activeTab === "places" && (
            <div className="flex gap-2">
              {!isOwnProfile ? (
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="outline" size="sm" data-testid="select-combined-filter">
                      {combinedFilterLabel}
                      <HugeiconsIcon icon={ArrowDown01Icon} className="h-3 w-3 text-muted-foreground" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end" className="whitespace-nowrap min-w-[200px]">
                    <DropdownMenuItem
                      onSelect={() => { setSelectedStatusFilter("all"); setSelectedListId("all"); }}
                      data-active={combinedFilterValue === "all"}
                    >
                      All
                      <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${combinedFilterValue === "all" ? "opacity-100" : "opacity-0"}`} />
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      onSelect={() => { setSelectedStatusFilter("been"); setSelectedListId("all"); }}
                      data-active={combinedFilterValue === "been"}
                    >
                      Places they've been
                      <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${combinedFilterValue === "been" ? "opacity-100" : "opacity-0"}`} />
                    </DropdownMenuItem>
                    {publicLists.length > 0 && <DropdownMenuSeparator />}
                    {publicLists.map((list) => (
                      <DropdownMenuItem
                        key={list.id}
                        onSelect={() => { setSelectedStatusFilter("all"); setSelectedListId(list.id); }}
                        data-active={combinedFilterValue === `list:${list.id}`}
                      >
                        {list.name}
                        <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${combinedFilterValue === `list:${list.id}` ? "opacity-100" : "opacity-0"}`} />
                      </DropdownMenuItem>
                    ))}
                  </DropdownMenuContent>
                </DropdownMenu>
              ) : (
                <>
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button variant="outline" size="sm" data-testid="select-status-filter">
                        {selectedStatusLabel}
                        <HugeiconsIcon icon={ArrowDown01Icon} className="h-3 w-3 text-muted-foreground" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      {statusOptions.map((option) => (
                        <DropdownMenuItem
                          key={option.value}
                          onSelect={() => setSelectedStatusFilter(option.value)}
                          data-active={selectedStatusFilter === option.value}
                        >
                          {option.label}
                          <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${selectedStatusFilter === option.value ? "opacity-100" : "opacity-0"}`} />
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                  {publicLists.length > 0 && (
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="outline" size="sm" data-testid="select-list-filter">
                          {selectedListLabel}
                          <HugeiconsIcon icon={ArrowDown01Icon} className="h-3 w-3 text-muted-foreground" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onSelect={() => setSelectedListId("all")}
                          data-active={selectedListId === "all"}
                        >
                          All Lists
                          <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${selectedListId === "all" ? "opacity-100" : "opacity-0"}`} />
                        </DropdownMenuItem>
                        {publicLists.map((list) => (
                          <DropdownMenuItem
                            key={list.id}
                            onSelect={() => setSelectedListId(list.id)}
                            data-active={selectedListId === list.id}
                          >
                            {list.name}
                            <HugeiconsIcon icon={Tick01Icon} className={`ml-auto h-4 w-4 ${selectedListId === list.id ? "opacity-100" : "opacity-0"}`} />
                          </DropdownMenuItem>
                        ))}
                      </DropdownMenuContent>
                    </DropdownMenu>
                  )}
                </>
              )}
            </div>
          )}
        </div>

          <TabsContent value="places" className="mt-0">
            <PlacesList
              places={filteredPlaces}
              selectedPlaceId={selectedPlaceId || null}
              onPlaceSelect={onPlaceSelect || (() => {})}
              placeRowRefs={placeRowRefs}
              showStatus={true}
              showSaveDropdown={true}
              emptyMessage="No places saved"
              emptySubMessage={isOwnProfile ? "Start saving places to see them here" : "This user hasn't saved any places yet"}
              thumbnailMode={isOwnProfile ? "my-places" : "photo"}
              currentUserPlaceData={resolvedCurrentUserPlaceData}
            />
          </TabsContent>

          <TabsContent value="feed" className="mt-0">
            {activities.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-12 text-center px-4">
                <HugeiconsIcon icon={Activity01Icon} className="mb-4 h-10 w-10 text-muted-foreground" />
                <p className="text-sm font-medium">No activity yet</p>
                <p className="text-xs text-muted-foreground mt-1">
                  {isOwnProfile ? "Your activity will appear here" : "This user doesn't have any activity yet"}
                </p>
              </div>
            ) : (
              <div className="divide-y">
                {activities.map((activity) => (
                  <FeedPost key={activity.id} activity={activity} />
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}

src/hooks/use-body-scroll-lock.ts.content:
"use client";

import { useEffect, useRef } from "react";

/**
 * Hook to lock body scroll when the bottom sheet is open.
 * Handles iOS Safari rubber-banding by using overflow hidden and touch-action.
 */
export function useBodyScrollLock(isLocked: boolean) {
  const scrollPositionRef = useRef(0);

  useEffect(() => {
    if (!isLocked) return;

    // Store current scroll position
    scrollPositionRef.current = window.scrollY;

    // Apply scroll lock styles
    const originalStyles = {
      overflow: document.body.style.overflow,
      position: document.body.style.position,
      top: document.body.style.top,
      left: document.body.style.left,
      right: document.body.style.right,
      touchAction: document.body.style.touchAction,
    };

    document.body.style.overflow = "hidden";
    document.body.style.position = "fixed";
    document.body.style.top = `-${scrollPositionRef.current}px`;
    document.body.style.left = "0";
    document.body.style.right = "0";
    document.body.style.touchAction = "none";

    // Also prevent scroll on document element for iOS
    const htmlEl = document.documentElement;
    const originalHtmlStyles = {
      overflow: htmlEl.style.overflow,
    };
    htmlEl.style.overflow = "hidden";

    return () => {
      // Restore original styles
      document.body.style.overflow = originalStyles.overflow;
      document.body.style.position = originalStyles.position;
      document.body.style.top = originalStyles.top;
      document.body.style.left = originalStyles.left;
      document.body.style.right = originalStyles.right;
      document.body.style.touchAction = originalStyles.touchAction;

      htmlEl.style.overflow = originalHtmlStyles.overflow;

      // Restore scroll position
      window.scrollTo(0, scrollPositionRef.current);
    };
  }, [isLocked]);
}

src/app/api/admin/import/instagram/profi.content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { enqueueJob } from "@/lib/worker/queue";
import { z } from "zod";

const importSchema = z.object({
  profileUrl: z.string().min(1),
  maxPosts: z.number().int().min(1).max(200).default(100),
});

export async function POST(request: NextRequest) {
  try {
    const user = await getCurrentUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();
    const parsed = importSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json(
        { error: "Invalid request", details: parsed.error.issues },
        { status: 400 }
      );
    }

    const { profileUrl, maxPosts } = parsed.data;

    const importJob = await prisma.importJob.create({
      data: {
        platform: "instagram",
        type: "profile",
        input: profileUrl,
        maxPosts,
        status: "pending",
      },
    });

    await enqueueJob("IMPORT_PROFILE", { importJobId: importJob.id });

    return NextResponse.json({
      importJobId: importJob.id,
      status: "pending",
    });
  } catch (error: any) {
    console.error("Import profile error:", error);
    return NextResponse.json(
      { error: error.message || "Failed to start import" },
      { status: 500 }
    );
  }
}

src/app/api/reviews/[id]/route.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { z } from "zod";

const updateReviewSchema = z.object({
  rating: z.number().int().min(0).max(10).optional(),
  note: z.string().optional().nullable(),
  visitedAt: z.string().datetime().optional().nullable(),
});

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    const review = await prisma.review.findUnique({
      where: { id },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            firstName: true,
            lastName: true,
            profileImageUrl: true,
          },
        },
        place: {
          select: {
            id: true,
            googlePlaceId: true,
            name: true,
          },
        },
        photos: {
          orderBy: { createdAt: "desc" },
        },
      },
    });

    if (!review) {
      return NextResponse.json({ error: "Review not found" }, { status: 404 });
    }

    return NextResponse.json(review);
  } catch (error: any) {
    console.error("Error fetching review:", error);
    return NextResponse.json({ error: "Failed to fetch review" }, { status: 500 });
  }
}

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await getCurrentUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { id } = await params;

    const review = await prisma.review.findUnique({ where: { id } });
    if (!review) {
      return NextResponse.json({ error: "Review not found" }, { status: 404 });
    }
    if (review.userId !== user.id) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const body = await request.json();
    const validated = updateReviewSchema.parse(body);

    const updatedReview = await prisma.review.update({
      where: { id },
      data: {
        ...(validated.rating !== undefined && { rating: validated.rating }),
        ...(validated.note !== undefined && { note: validated.note }),
        ...(validated.visitedAt !== undefined && {
          visitedAt: validated.visitedAt ? new Date(validated.visitedAt) : null,
        }),
      },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            firstName: true,
            lastName: true,
            profileImageUrl: true,
          },
        },
        place: {
          select: {
            id: true,
            googlePlaceId: true,
            name: true,
          },
        },
        photos: true,
      },
    });

    return NextResponse.json(updatedReview);
  } catch (error: any) {
    if (error.name === "ZodError") {
      return NextResponse.json({ error: "Validation failed", details: error.errors }, { status: 400 });
    }
    console.error("Error updating review:", error);
    return NextResponse.json({ error: "Failed to update review" }, { status: 500 });
  }
}

export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const user = await getCurrentUser();
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { id } = await params;

    const review = await prisma.review.findUnique({ where: { id } });
    if (!review) {
      return NextResponse.json({ error: "Review not found" }, { status: 404 });
    }
    if (review.userId !== user.id) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    await prisma.review.delete({ where: { id } });
    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error("Error deleting review:", error);
    return NextResponse.json({ error: "Failed to delete review" }, { status: 500 });
  }
}

src/lib/worker/handlers/enrich-review.ts.content:
import { prisma } from "@/lib/prisma";

interface EnrichReviewPayload {
  reviewId: string;
}

const MIN_TAG_CONFIDENCE = 0.55;

export async function handleEnrichReview(payload: EnrichReviewPayload) {
  const { reviewId } = payload;

  const review = await prisma.review.findUnique({
    where: { id: reviewId },
    include: {
      place: true,
    },
  });
  if (!review) throw new Error(`Review ${reviewId} not found`);

  const text = review.socialPostCaption || review.note || "";
  if (!text || text.length < 10) return;

  const allTags = await prisma.tag.findMany({
    include: { category: true },
  });

  const tagsByCategory: Record<string, Array<{ slug: string; displayName: string; id: string }>> = {};
  for (const tag of allTags) {
    const catSlug = tag.category.slug;
    if (!tagsByCategory[catSlug]) tagsByCategory[catSlug] = [];
    tagsByCategory[catSlug].push({
      slug: tag.slug,
      displayName: tag.displayName,
      id: tag.id,
    });
  }

  const taxonomyDescription = Object.entries(tagsByCategory)
    .map(
      ([cat, tags]) =>
        `${cat}: ${tags.map((t) => t.slug).join(", ")}`
    )
    .join("\n");

  const openaiKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY || process.env.OPENAI_API_KEY;
  if (!openaiKey) throw new Error("OpenAI API key not configured");

  const prompt = `You are a food/restaurant tag extractor. Given a social media post caption about a restaurant/bar/cafe, extract relevant tags from the controlled vocabulary below.

TAXONOMY:
${taxonomyDescription}

CONTEXT:
Place: ${review.place.name}${review.place.neighborhood ? `, ${review.place.neighborhood}` : ""}
Google types: ${JSON.stringify(review.place.types || [])}

CAPTION:
${text.substring(0, 1000)}

Return a JSON object where keys are tag slugs from the taxonomy above, and values are confidence scores (0.0 to 1.0). Only include tags that are relevant. Be conservative - only assign high confidence (>0.8) when the caption clearly indicates that tag.

Example response format:
{"smashburger_food": 0.9, "casual_hang": 0.7, "affordable": 0.6}

Return ONLY the JSON object, no other text.`;

  const baseUrl = process.env.AI_INTEGRATIONS_OPENAI_BASE_URL || "https://api.openai.com/v1";
  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${openaiKey}`,
    },
    body: JSON.stringify({
      model: "gpt-4o-mini",
      messages: [{ role: "user", content: prompt }],
      temperature: 0.1,
      max_tokens: 500,
      response_format: { type: "json_object" },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`OpenAI API error: ${response.status} ${errorText}`);
  }

  const data = await response.json();
  const content = data.choices?.[0]?.message?.content;
  if (!content) return;

  let tagScores: Record<string, number>;
  try {
    tagScores = JSON.parse(content);
  } catch {
    console.error("[EnrichReview] Failed to parse AI response:", content);
    return;
  }

  const tagMap = new Map(allTags.map((t) => [t.slug, t]));

  for (const [slug, confidence] of Object.entries(tagScores)) {
    if (typeof confidence !== "number" || confidence < MIN_TAG_CONFIDENCE) continue;

    const tag = tagMap.get(slug);
    if (!tag) continue;

    await prisma.reviewTag.upsert({
      where: {
        reviewId_tagId: {
          reviewId,
          tagId: tag.id,
        },
      },
      update: {
        confidence: Math.min(1, confidence),
        source: "ai",
      },
      create: {
        reviewId,
        tagId: tag.id,
        source: "ai",
        confidence: Math.min(1, confidence),
      },
    });
  }
}

