import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { createActivity } from "@/lib/activity";

async function ensureSystemLists(userId: string) {
  const wantToGoList = await prisma.list.findFirst({
    where: { userId, systemSlug: "want-to-go" },
  });

  if (!wantToGoList) {
    await prisma.list.create({
      data: {
        userId,
        name: "Want to Go",
        description: "Places you want to visit",
        visibility: "PRIVATE",
        isSystem: true,
        systemSlug: "want-to-go",
      },
    });
  }
}

export async function GET() {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    await ensureSystemLists(user.id);

    const myLists = await prisma.list.findMany({
      where: { userId: user.id },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            firstName: true,
            lastName: true,
            profileImageUrl: true,
          },
        },
        listPlaces: {
          take: 5,
          orderBy: { addedAt: "desc" },
          include: {
            place: {
              select: {
                id: true,
                name: true,
                formattedAddress: true,
                photoRefs: true,
              },
            },
          },
        },
        _count: {
          select: { listPlaces: true },
        },
      },
      orderBy: [
        { isSystem: "desc" },
        { createdAt: "desc" },
      ],
    });

    const discoverLists = await prisma.list.findMany({
      where: {
        userId: { not: user.id },
        visibility: "PUBLIC",
        isSystem: false,
      },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            firstName: true,
            lastName: true,
            profileImageUrl: true,
          },
        },
        listPlaces: {
          take: 5,
          orderBy: { addedAt: "desc" },
          include: {
            place: {
              select: {
                id: true,
                name: true,
                formattedAddress: true,
                photoRefs: true,
              },
            },
          },
        },
        _count: {
          select: { listPlaces: true },
        },
      },
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json({ lists: myLists, discoverLists });
  } catch (error: any) {
    console.error("Get lists error:", error);
    return NextResponse.json({ error: "Failed to get lists" }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const body = await request.json();
    const { name, description, visibility } = body;

    if (!name || typeof name !== "string" || name.trim().length === 0) {
      return NextResponse.json({ error: "Name is required" }, { status: 400 });
    }

    if (visibility && visibility !== "PRIVATE" && visibility !== "PUBLIC") {
      return NextResponse.json({ error: "Invalid visibility. Must be PRIVATE or PUBLIC" }, { status: 400 });
    }

    const list = await prisma.list.create({
      data: {
        userId: user.id,
        name: name.trim(),
        description: description?.trim() || null,
        visibility: visibility || "PRIVATE",
        isSystem: false,
      },
      include: {
        _count: {
          select: { listPlaces: true },
        },
      },
    });

    await createActivity({
      actorId: user.id,
      type: "LIST_CREATED",
      listId: list.id,
      metadata: { listName: list.name },
    });

    return NextResponse.json({ list });
  } catch (error: any) {
    console.error("Create list error:", error);
    return NextResponse.json({ error: "Failed to create list" }, { status: 500 });
  }
}

src/components/sidebars/list-sidebar.tsx.content:
"use client";

import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { SidebarTrigger } from "@/components/ui/sidebar";
import { HugeiconsIcon } from "@hugeicons/react";
import { LockIcon, Share01Icon, Tick01Icon } from "@hugeicons/core-free-icons";
import { toast } from "sonner";
import { useState } from "react";
import type { SidebarInjectedProps } from "@/components/map/map-layout";
import { PlacesList } from "@/components/shared/places-list";

interface Place {
  id: string;
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  lat: number;
  lng: number;
  primaryType: string | null;
  types: string[] | null;
  priceLevel: string | null;
  photoRefs: string[] | null;
}

interface ListPlace {
  id: string;
  listId: string;
  placeId: string;
  addedAt: string;
  emoji?: string | null;
  place: Place;
}

interface ListOwner {
  id: string;
  username: string | null;
  firstName: string | null;
  lastName: string | null;
  profileImageUrl: string | null;
}

interface CurrentUserPlaceData {
  savedPlaceId: string | null;
  hasBeen: boolean;
  rating: number | null;
  lists: Array<{ id: string; name: string }>;
}

interface ListData {
  id: string;
  name: string;
  description: string | null;
  visibility: "PRIVATE" | "PUBLIC";
  userId: string;
  createdAt: string;
  user: ListOwner;
  listPlaces: ListPlace[];
}

interface ListSidebarProps extends Partial<SidebarInjectedProps> {
  list: ListData | null;
  isLoading?: boolean;
  isOwner: boolean;
  currentUserId?: string;
  onRemovePlace?: (placeId: string) => void;
  isRemovingPlace?: boolean;
  currentUserPlaceData?: Record<string, CurrentUserPlaceData> | null;
}

export function ListSidebar({
  list,
  isLoading = false,
  isOwner,
  currentUserId,
  selectedPlaceId,
  onPlaceSelect,
  placeRowRefs,
  onRemovePlace,
  isRemovingPlace = false,
  currentUserPlaceData,
}: ListSidebarProps) {
  const [copied, setCopied] = useState(false);

  const handleShare = () => {
    const url = `${window.location.origin}/lists/${list?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      toast.success("Link copied to clipboard!");
      setTimeout(() => setCopied(false), 2000);
    }).catch(() => {
      toast.error("Failed to copy link");
    });
  };

  const savedPlaces = list?.listPlaces.map(lp => ({
    id: lp.id,
    placeId: lp.placeId,
    hasBeen: false,
    rating: null,
    emoji: lp.emoji || null,
    createdAt: lp.addedAt,
    place: lp.place,
  })) || [];

  const ownerHandle = list?.user.username || list?.user.id || "";

  if (isLoading || !list) {
    return (
      <div className="h-full flex flex-col bg-background">
        <div className="flex items-center gap-2 p-3 border-b">
          <SidebarTrigger data-testid="button-sidebar-toggle" />
          <Skeleton className="h-4 w-20" />
        </div>
        <div className="p-3 border-b space-y-1">
          <Skeleton className="h-4 w-32" />
          <Skeleton className="h-3 w-24" />
        </div>
        <div className="p-2 space-y-2">
          <Skeleton className="h-16 w-full" />
          <Skeleton className="h-16 w-full" />
          <Skeleton className="h-16 w-full" />
        </div>
      </div>
    );
  }

  const placeCount = list.listPlaces.length;

  return (
    <div className="h-full flex flex-col bg-background" data-testid="list-sidebar">
      <div className="flex items-center gap-2 p-3 border-b">
        <SidebarTrigger className="hidden md:flex" data-testid="button-sidebar-toggle" />
        <span className="font-semibold text-sm flex-1 font-brand">{list.name}</span>
        {list.visibility === "PUBLIC" && (
          <Button
            variant="ghost"
            size="icon"
            onClick={handleShare}
            title="Share list"
            data-testid="button-share-list"
          >
            {copied ? <HugeiconsIcon icon={Tick01Icon} className="h-4 w-4" /> : <HugeiconsIcon icon={Share01Icon} className="h-4 w-4" />}
          </Button>
        )}
        {list.visibility === "PRIVATE" && (
          <span title="Private list">
            <HugeiconsIcon icon={LockIcon} className="h-4 w-4 text-muted-foreground" />
          </span>
        )}
      </div>

      <div className="flex items-center justify-between px-3 py-2 border-b">
        <div className="min-w-0">
          <Link 
            href={`/u/${ownerHandle}`} 
            className="text-xs text-muted-foreground hover:underline"
            data-testid="link-list-owner"
          >
            by @{ownerHandle}
          </Link>
        </div>
        <span className="text-xs text-muted-foreground shrink-0">{placeCount} {placeCount === 1 ? "place" : "places"}</span>
      </div>

      <div className="flex-1 overflow-y-auto">
        <PlacesList
          places={savedPlaces}
          selectedPlaceId={selectedPlaceId || null}
          onPlaceSelect={onPlaceSelect || (() => {})}
          placeRowRefs={placeRowRefs}
          showStatus={false}
          showSaveDropdown={true}
          hideDropdownUntilHover={true}
          thumbnailMode="emoji"
          emojiEditable={isOwner}
          currentUserPlaceData={currentUserPlaceData || undefined}
          emptyMessage="No places in this list"
          emptySubMessage={isOwner ? "Add places from your saved places" : "This list is empty"}
        />
      </div>
    </div>
  );
}

