"use client";

import Link from "next/link";
import Image from "next/image";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { HugeiconsIcon } from "@hugeicons/react";
import { FavouriteIcon, Comment01Icon, Bookmark01Icon, AddToListIcon } from "@hugeicons/core-free-icons";
import { SocialPostCard } from "@/components/shared/social-post-card";

interface ActivityActor {
  id: string;
  username: string | null;
  firstName: string | null;
  lastName: string | null;
  profileImageUrl: string | null;
}

interface ActivityPlace {
  id: string;
  googlePlaceId: string;
  name: string;
  formattedAddress: string;
  photoRefs?: string[] | null;
}

interface ActivityList {
  id: string;
  name: string;
  visibility: string;
  userId: string | null;
}

interface SocialPostData {
  author: string;
  authorImage?: string | null;
  caption?: string | null;
  mediaUrl?: string | null;
  mediaType?: string | null;
  likes?: number | null;
  postedAt?: string | null;
  permalink?: string | null;
  source?: 'instagram' | 'tiktok' | 'manual' | string | null;
}

interface Activity {
  id: string;
  actorId: string;
  type: "PLACE_SAVED" | "PLACE_MARKED_BEEN" | "PLACE_ADDED_TO_LIST" | "LIST_CREATED" | "REVIEW_CREATED";
  placeId: string | null;
  listId: string | null;
  metadata: { placeName?: string; listName?: string; rating?: number; note?: string; review_preview?: string } | null;
  createdAt: string;
  actor: ActivityActor;
  place: ActivityPlace | null;
  list: ActivityList | null;
  socialPost?: SocialPostData | null;
}

const RATING_COLORS: Record<number, string> = {
  1: "bg-red-500",
  2: "bg-yellow-500", 
  3: "bg-green-500",
};

function formatTimeAgo(dateString: string) {
  const date = new Date(dateString);
  const now = new Date();
  const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (seconds < 60) return "now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d ago`;
  return date.toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

interface FeedPostProps {
  activity: Activity;
}

export function FeedPost({ activity }: FeedPostProps) {
  const actorName = activity.actor.firstName && activity.actor.lastName
    ? `${activity.actor.firstName} ${activity.actor.lastName}`
    : activity.actor.username || "User";

  const actorInitials = activity.actor.firstName && activity.actor.lastName
    ? `${activity.actor.firstName[0]}${activity.actor.lastName[0]}`
    : actorName.charAt(0).toUpperCase();

  const actorLink = `/u/${activity.actor.username || activity.actor.id}`;
  const placeName = activity.place?.name || activity.metadata?.placeName;
  const photoUrl = activity.place?.photoRefs?.[0]
    ? `/api/places/photo?photoRef=${encodeURIComponent(activity.place.photoRefs[0])}&maxWidth=600`
    : null;

  const reviewText = activity.metadata?.note || activity.metadata?.review_preview;
  const rating = activity.metadata?.rating;
  const hasSocialPost = !!activity.socialPost?.permalink;

  // For posts with social embeds, use different layout
  if (hasSocialPost) {
    const igBorder = '#dbdbdb';

    return (
      <article className="bg-card border-0" data-testid={`feed-post-${activity.id}`}>
        {/* Tab-style location header with inverted corner radii */}
        {activity.place && (
          <div className="flex items-end pl-4" data-testid={`feed-place-${activity.id}`}>
            <div
              className="w-[10px] h-[10px] flex-shrink-0"
              style={{ background: `radial-gradient(circle at 0% 0, transparent 10px, ${igBorder} 10px)` }}
            />
            <Link
              href={`/places/${activity.place.googlePlaceId}`}
              className="px-3 py-1 text-xs font-medium truncate max-w-[70%]"
              style={{
                background: igBorder,
                borderRadius: '8px 8px 0 0',
                color: '#262626',
              }}
            >
              Visited {activity.place.name}
            </Link>
            <div
              className="w-[10px] h-[10px] flex-shrink-0"
              style={{ background: `radial-gradient(circle at 100% 0, transparent 10px, ${igBorder} 10px)` }}
            />
            <div className="flex-1" />
            <Button variant="ghost" size="icon" className="mb-[-2px] mr-1 text-muted-foreground" data-testid={`feed-save-${activity.id}`}>
              <HugeiconsIcon icon={Bookmark01Icon} className="h-5 w-5" />
            </Button>
          </div>
        )}

        {/* Full-width Instagram embed */}
        <SocialPostCard
          author={activity.socialPost!.author}
          authorImage={activity.socialPost!.authorImage}
          caption={activity.socialPost!.caption}
          mediaUrl={activity.socialPost!.mediaUrl}
          mediaType={activity.socialPost!.mediaType}
          likes={activity.socialPost!.likes}
          postedAt={activity.socialPost!.postedAt}
          permalink={activity.socialPost!.permalink}
          source={activity.socialPost!.source as 'instagram' | 'tiktok' | 'manual' | undefined}
        />
      </article>
    );
  }

  // Standard layout for non-social posts
  return (
    <article className="bg-card" data-testid={`feed-post-${activity.id}`}>
      <div className="p-4">
        {/* Header: Avatar + "Name @ Place" */}
        <div className="flex items-start gap-2">
          <Link href={actorLink} data-testid={`feed-avatar-${activity.id}`}>
            <Avatar className="h-8 w-8">
              <AvatarImage src={activity.actor.profileImageUrl || undefined} alt={actorName} />
              <AvatarFallback className="text-sm">{actorInitials}</AvatarFallback>
            </Avatar>
          </Link>
          <div className="flex-1 min-w-0">
            {/* Name @ Place + Action */}
            <div className="flex items-center gap-1 flex-wrap">
              <Link href={actorLink} className="text-sm font-medium hover:underline" data-testid={`feed-author-${activity.id}`}>
                {actorName}
              </Link>
              {placeName && (
                <>
                  <span className="text-sm text-muted-foreground">@</span>
                  {activity.place ? (
                    <Link 
                      href={`/places/${activity.place.googlePlaceId}`} 
                      className="text-sm font-medium hover:underline"
                      data-testid={`feed-place-name-${activity.id}`}
                    >
                      {placeName}
                    </Link>
                  ) : (
                    <span className="text-sm font-medium">{placeName}</span>
                  )}
                </>
              )}
              {/* Action indicator */}
              {activity.type === "PLACE_MARKED_BEEN" && (
                <span className="text-sm flex items-center gap-1 text-muted-foreground">
                  <span>·</span>
                  <span 
                    className={`inline-block w-2.5 h-2.5 rounded-full ${rating ? RATING_COLORS[rating] : "bg-green-500"}`} 
                  />
                  <span>Been</span>
                </span>
              )}
              {activity.type === "PLACE_SAVED" && (
                <span className="flex items-center gap-1 text-muted-foreground">
                  <span>·</span>
                  <HugeiconsIcon icon={Bookmark01Icon} className="h-3 w-3" />
                  <span>Saved</span>
                </span>
              )}
              {activity.type === "PLACE_ADDED_TO_LIST" && activity.list && (
                <span className="flex items-center gap-1 text-muted-foreground">
                  <span>·</span>
                  <span>added to</span>
                  <Link 
                    href={`/lists/${activity.list.id}`} 
                    className="font-medium hover:underline text-foreground"
                  >
                    {activity.list.name}
                  </Link>
                </span>
              )}
              {activity.type === "LIST_CREATED" && activity.list && (
                <>
                  <span className="text-muted-foreground">created</span>
                  <Link 
                    href={`/lists/${activity.list.id}`} 
                    className="font-medium hover:underline"
                  >
                    {activity.list.name}
                  </Link>
                </>
              )}
            </div>

            {/* Timestamp */}
            <p className="text-xs text-muted-foreground mt-0.5">
              {formatTimeAgo(activity.createdAt)}
            </p>

            {/* Rating (if review) */}
            {activity.type === "REVIEW_CREATED" && rating && (
              <div className="flex items-center gap-0.5 mt-1" data-testid={`feed-rating-${activity.id}`}>
                {[...Array(10)].map((_, i) => (
                  <span
                    key={i}
                    className={`text-sm ${i < rating ? "text-amber-500" : "text-muted-foreground/30"}`}
                  >
                    ●
                  </span>
                ))}
                <span className="text-sm text-muted-foreground ml-1.5">{rating}/10</span>
              </div>
            )}
          </div>
        </div>

        {/* Place Photo Card */}
        {activity.place && photoUrl && (
          <Link
            href={`/places/${activity.place.googlePlaceId}`}
            className="block mt-3 rounded-lg overflow-hidden border"
            data-testid={`feed-place-${activity.id}`}
          >
            <div className="relative aspect-[16/9] bg-muted">
              <Image
                src={photoUrl}
                alt={activity.place.name}
                fill
                className="object-cover"
                sizes="(max-width: 640px) 100vw, 500px"
                unoptimized
              />
            </div>
            <div className="p-3 bg-muted/30">
              <p className="font-medium text-sm">{activity.place.name}</p>
              <p className="text-xs text-muted-foreground mt-0.5">{activity.place.formattedAddress}</p>
            </div>
          </Link>
        )}

        {/* Place Card without photo */}
        {activity.place && !photoUrl && (
          <Link
            href={`/places/${activity.place.googlePlaceId}`}
            className="block mt-3 p-3 rounded-lg border bg-muted/30 hover:bg-muted/50 transition-colors"
            data-testid={`feed-place-${activity.id}`}
          >
            <p className="font-medium text-sm">{activity.place.name}</p>
            <p className="text-xs text-muted-foreground mt-0.5">{activity.place.formattedAddress}</p>
          </Link>
        )}

        {/* Review Text */}
        {reviewText && (
          <p className="text-sm leading-relaxed mt-3" data-testid={`feed-note-${activity.id}`}>
            {reviewText}
          </p>
        )}

        {/* Social Action Buttons */}
        <div className="flex items-center gap-1 mt-3 -ml-2">
          <Button variant="ghost" size="icon" className="h-9 w-9 text-muted-foreground hover:text-foreground" data-testid={`feed-like-${activity.id}`}>
            <HugeiconsIcon icon={FavouriteIcon} className="h-5 w-5" />
          </Button>
          <Button variant="ghost" size="icon" className="h-9 w-9 text-muted-foreground hover:text-foreground" data-testid={`feed-comment-${activity.id}`}>
            <HugeiconsIcon icon={Comment01Icon} className="h-5 w-5" />
          </Button>
          <Button variant="ghost" size="icon" className="h-9 w-9 text-muted-foreground hover:text-foreground" data-testid={`feed-save-${activity.id}`}>
            <HugeiconsIcon icon={Bookmark01Icon} className="h-5 w-5" />
          </Button>
          <Button variant="ghost" size="icon" className="h-9 w-9 text-muted-foreground hover:text-foreground" data-testid={`feed-add-list-${activity.id}`}>
            <HugeiconsIcon icon={AddToListIcon} className="h-5 w-5" />
          </Button>
        </div>
      </div>
    </article>
  );
}

src/lib/auto-tag-place.ts.content:
import { prisma } from "@/lib/prisma";

export async function autoTagPlace(placeId: string, force = false): Promise<void> {
  try {
    const place = await prisma.place.findUnique({
      where: { id: placeId },
      include: {
        reviews: {
          select: { socialPostCaption: true, note: true },
          take: 5,
        },
        placeTags: {
          select: { id: true, source: true },
        },
      },
    });

    if (!place) return;

    const existingTags = place.placeTags.length;
    if (existingTags > 0 && !force) {
      const hasReviews = place.reviews.some(r => (r.socialPostCaption || r.note || "").length > 5);
      const allBasicAi = place.placeTags.every(t => t.source === "ai");
      if (!hasReviews || !allBasicAi) return;
    }

    const openaiKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY || process.env.OPENAI_API_KEY;
    if (!openaiKey) return;

    const allTags = await prisma.tag.findMany({
      include: { category: true },
    });

    const tagMap = new Map(allTags.map((t) => [t.slug, t]));
    const allSlugs = allTags.map((t) => t.slug);

    const captions = place.reviews
      .map((r) => r.socialPostCaption || r.note || "")
      .filter((c) => c.length > 5)
      .slice(0, 3)
      .join("\n---\n");

    const prompt = `You tag restaurants/bars/places. Pick 3-5 tags from ONLY this list:

${allSlugs.join(", ")}

Place: "${place.name}"
${place.neighborhood ? `Neighborhood: ${place.neighborhood}` : ""}
Type: ${place.primaryType || "unknown"}
Google types: ${(place.types as string[] || []).slice(0, 5).join(", ")}
${captions ? `Reviews: ${captions.substring(0, 500)}` : ""}

Return ONLY a flat JSON object like {"tag_slug": 0.9, "another_slug": 0.8}. Keys must be exact slugs from the list above. Values are confidence 0.6-1.0.`;

    const baseUrl = process.env.AI_INTEGRATIONS_OPENAI_BASE_URL || "https://api.openai.com/v1";
    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${openaiKey}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [{ role: "user", content: prompt }],
        temperature: 0.1,
        max_tokens: 200,
        response_format: { type: "json_object" },
      }),
    });

    if (!response.ok) {
      console.error(`[AutoTagPlace] OpenAI error for ${place.name}: ${response.status}`);
      return;
    }

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content;
    if (!content) return;

    let parsed: Record<string, any>;
    try {
      parsed = JSON.parse(content);
    } catch {
      console.error(`[AutoTagPlace] Failed to parse response for ${place.name}: ${content}`);
      return;
    }

    const tagScores: Record<string, number> = {};
    for (const [key, value] of Object.entries(parsed)) {
      if (typeof value === "number") {
        tagScores[key] = value;
      } else if (typeof value === "object" && value !== null) {
        for (const [nestedKey, nestedValue] of Object.entries(value as Record<string, unknown>)) {
          if (typeof nestedValue === "number") {
            tagScores[nestedKey] = nestedValue;
          }
        }
      }
    }

    const tagSource = "ai" as const;

    let tagCount = 0;
    for (const [slug, confidence] of Object.entries(tagScores)) {
      if (typeof confidence !== "number" || confidence < 0.5) continue;
      const tag = tagMap.get(slug);
      if (!tag) continue;

      await prisma.placeTag.upsert({
        where: {
          placeId_tagId: {
            placeId: place.id,
            tagId: tag.id,
          },
        },
        update: {
          confidence: Math.min(1, confidence),
          source: tagSource,
        },
        create: {
          placeId: place.id,
          tagId: tag.id,
          source: tagSource,
          confidence: Math.min(1, confidence),
        },
      });
      tagCount++;
    }

    if (tagCount > 0) {
      console.log(`[AutoTagPlace] Tagged ${place.name} with ${tagCount} tags${force ? " (forced refresh)" : ""}`);
    } else {
      console.warn(`[AutoTagPlace] No matching tags for ${place.name}. AI returned: ${content}`);
    }
  } catch (err: any) {
    console.error(`[AutoTagPlace] Error for place ${placeId}:`, err.message);
  }
}

src/app/api/places/backfill-summaries/ro.content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { autoSummaryPlace } from "@/lib/auto-summary-place";

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const placesWithoutSummary = await prisma.place.findMany({
      where: {
        OR: [
          { aiSummary: null },
          { aiSummary: "" },
        ],
      },
      select: { id: true, name: true },
      orderBy: { createdAt: "desc" },
    });

    if (placesWithoutSummary.length === 0) {
      return NextResponse.json({ message: "All places already have summaries", summarized: 0 });
    }

    let summarized = 0;
    let failed = 0;

    for (const place of placesWithoutSummary) {
      try {
        await autoSummaryPlace(place.id);
        const updated = await prisma.place.findUnique({
          where: { id: place.id },
          select: { aiSummary: true },
        });
        if (updated?.aiSummary) {
          summarized++;
        } else {
          failed++;
        }
      } catch (err: any) {
        failed++;
      }
      await new Promise((r) => setTimeout(r, 300));
    }

    return NextResponse.json({
      message: `Backfill complete: ${summarized} summarized, ${failed} failed out of ${placesWithoutSummary.length}`,
      summarized,
      failed,
      total: placesWithoutSummary.length,
    });
  } catch (err: any) {
    console.error("[BackfillSummaries] Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

src/app/api/places/backfill-tags/route.t.content:
import { NextRequest, NextResponse } from "next/server";
import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { autoTagPlace } from "@/lib/auto-tag-place";

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const placesWithoutTags = await prisma.place.findMany({
      where: {
        placeTags: { none: {} },
      },
      select: { id: true, name: true },
      orderBy: { createdAt: "desc" },
    });

    if (placesWithoutTags.length === 0) {
      return NextResponse.json({ message: "All places already have tags", tagged: 0 });
    }

    let tagged = 0;
    let failed = 0;
    const results: Array<{ name: string; status: string }> = [];

    for (const place of placesWithoutTags) {
      try {
        await autoTagPlace(place.id);
        const count = await prisma.placeTag.count({ where: { placeId: place.id } });
        if (count > 0) {
          tagged++;
          results.push({ name: place.name, status: `tagged (${count} tags)` });
        } else {
          failed++;
          results.push({ name: place.name, status: "no tags assigned" });
        }
      } catch (err: any) {
        failed++;
        results.push({ name: place.name, status: `error: ${err.message}` });
      }
      await new Promise((r) => setTimeout(r, 300));
    }

    return NextResponse.json({
      message: `Backfill complete: ${tagged} tagged, ${failed} failed out of ${placesWithoutTags.length}`,
      tagged,
      failed,
      total: placesWithoutTags.length,
      results,
    });
  } catch (err: any) {
    console.error("[BackfillTags] Error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

src/app/api/admin/backfill-avatars/route.content:
import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST() {
  const users = await prisma.user.findMany({
    where: {
      isInstagramImport: true,
      OR: [{ profileImageUrl: null }, { profileImageUrl: "" }],
    },
    select: { id: true, instagramHandle: true, username: true },
  });

  if (users.length === 0) {
    return NextResponse.json({ message: "All imported users already have avatars" });
  }

  const apifyToken = process.env.APIFY_TOKEN;
  if (!apifyToken) {
    return NextResponse.json({ error: "APIFY_TOKEN not configured" }, { status: 500 });
  }

  const handles = users.map((u) => u.instagramHandle || u.username).filter(Boolean) as string[];

  try {
    const runResponse = await fetch(
      "https://api.apify.com/v2/acts/apify~instagram-profile-scraper/runs?waitForFinish=120",
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${apifyToken}`,
        },
        body: JSON.stringify({ usernames: handles }),
      }
    );

    if (!runResponse.ok) {
      return NextResponse.json({ error: `Apify failed: ${runResponse.status}` }, { status: 500 });
    }

    const runData = await runResponse.json();
    const datasetId = runData.data?.defaultDatasetId;
    if (!datasetId) {
      return NextResponse.json({ error: "No dataset returned" }, { status: 500 });
    }

    const itemsRes = await fetch(
      `https://api.apify.com/v2/datasets/${datasetId}/items?format=json`,
      { headers: { Authorization: `Bearer ${apifyToken}` } }
    );
    const profiles = await itemsRes.json();

    let updated = 0;
    for (const profile of profiles) {
      const picUrl = profile.profilePicUrlHD || profile.profilePicUrl;
      const handle = profile.username;
      if (!picUrl || !handle) continue;

      const user = users.find(
        (u) => u.instagramHandle === handle || u.username === handle
      );
      if (!user) continue;

      await prisma.user.update({
        where: { id: user.id },
        data: { profileImageUrl: picUrl },
      });
      updated++;
      console.log(`Updated avatar for @${handle}`);
    }

    return NextResponse.json({ total: users.length, updated });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

src/lib/auto-summary-place.ts.content:
import { prisma } from "@/lib/prisma";

export async function autoSummaryPlace(placeId: string, force = false): Promise<void> {
  try {
    const place = await prisma.place.findUnique({
      where: { id: placeId },
      include: {
        placeTags: {
          include: { tag: { include: { category: true } } },
          orderBy: { confidence: "desc" },
          take: 10,
        },
        reviews: {
          select: { socialPostCaption: true, note: true },
          take: 3,
        },
      },
    });

    if (!place) return;

    if (place.aiSummary && !force) {
      const hasReviews = place.reviews.some(r => (r.socialPostCaption || r.note || "").length > 5);
      const summaryAge = place.aiSummaryUpdatedAt
        ? Date.now() - new Date(place.aiSummaryUpdatedAt).getTime()
        : Infinity;
      const isStale = summaryAge > 7 * 24 * 60 * 60 * 1000;
      if (!(hasReviews && isStale)) return;
    }

    const openaiKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY || process.env.OPENAI_API_KEY;
    if (!openaiKey) return;

    const tagsByCategory: Record<string, string[]> = {};
    for (const pt of place.placeTags) {
      const catSlug = pt.tag.category.slug;
      if (!tagsByCategory[catSlug]) tagsByCategory[catSlug] = [];
      tagsByCategory[catSlug].push(pt.tag.displayName);
    }

    const captions = place.reviews
      .map((r) => r.socialPostCaption || r.note || "")
      .filter((c) => c.length > 5)
      .slice(0, 3);

    const prompt = `Write a 2-sentence summary for "${place.name}"${place.neighborhood ? ` in ${place.neighborhood}` : place.locality ? ` in ${place.locality}` : ""}.

Type: ${place.primaryType || "establishment"}
${place.types ? `Categories: ${(place.types as string[]).slice(0, 5).join(", ")}` : ""}
${Object.keys(tagsByCategory).length > 0 ? `Tags: ${JSON.stringify(tagsByCategory)}` : ""}
${captions.length > 0 ? `\nReview snippets:\n${captions.map((c, i) => `${i + 1}. ${c.substring(0, 150)}`).join("\n")}` : ""}

Write a concise, specific summary for a place discovery app. Mention what kind of food/drinks they serve or what makes them special. Be specific, not generic. Do NOT use emojis. Do NOT say "Known for great ambiance and quality service" or similar filler.`;

    const baseUrl = process.env.AI_INTEGRATIONS_OPENAI_BASE_URL || "https://api.openai.com/v1";
    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${openaiKey}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [{ role: "user", content: prompt }],
        temperature: 0.7,
        max_tokens: 150,
      }),
    });

    if (!response.ok) {
      console.error(`[AutoSummaryPlace] OpenAI error for ${place.name}: ${response.status}`);
      return;
    }

    const data = await response.json();
    const summary = data.choices?.[0]?.message?.content?.trim();
    if (!summary) return;

    await prisma.place.update({
      where: { id: placeId },
      data: {
        aiSummary: summary,
        aiSummaryUpdatedAt: new Date(),
      },
    });

    console.log(`[AutoSummaryPlace] Generated summary for ${place.name}${force ? " (forced refresh)" : ""}`);
  } catch (err: any) {
    console.error(`[AutoSummaryPlace] Error for place ${placeId}:`, err.message);
  }
}

src/app/api/proxy-image/route.ts.content:
import { NextRequest, NextResponse } from "next/server";

export async function GET(request: NextRequest) {
  const url = request.nextUrl.searchParams.get("url");

  if (!url) {
    return new NextResponse("Missing url parameter", { status: 400 });
  }

  try {
    new URL(url);
  } catch {
    return new NextResponse("Invalid URL", { status: 400 });
  }

  try {
    const response = await fetch(url, {
      headers: {
        "User-Agent": "Mozilla/5.0 (compatible; TwnSq/1.0)",
      },
    });

    if (!response.ok) {
      return new NextResponse("Failed to fetch image", { status: response.status });
    }

    const contentType = response.headers.get("content-type") || "image/jpeg";
    const buffer = await response.arrayBuffer();

    return new NextResponse(Buffer.from(buffer), {
      headers: {
        "Content-Type": contentType,
        "Cache-Control": "public, max-age=86400",
      },
    });
  } catch {
    return new NextResponse("Failed to proxy image", { status: 502 });
  }
}

src/components/ui/map.tsx.content:
"use client";

import {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { createPortal } from "react-dom";
import { cn } from "@/lib/utils";
import { loadGoogleMaps } from "@/lib/google-maps-loader";

type MapContextValue = {
  map: google.maps.Map | null;
  isLoaded: boolean;
};

const MapContext = createContext<MapContextValue | null>(null);

function useMap() {
  const context = useContext(MapContext);
  if (!context) {
    throw new Error("useMap must be used within a Map component");
  }
  return context;
}

type MapRef = google.maps.Map;

type MapProps = {
  children?: ReactNode;
  className?: string;
  center?: [number, number];
  zoom?: number;
  mapTypeId?: string;
  styles?: google.maps.MapTypeStyle[];
  disableDefaultUI?: boolean;
};

const DefaultLoader = () => (
  <div className="absolute inset-0 flex items-center justify-center bg-muted">
    <div className="flex gap-1">
      <span className="size-1.5 rounded-full bg-muted-foreground/60 animate-pulse" />
      <span className="size-1.5 rounded-full bg-muted-foreground/60 animate-pulse [animation-delay:150ms]" />
      <span className="size-1.5 rounded-full bg-muted-foreground/60 animate-pulse [animation-delay:300ms]" />
    </div>
  </div>
);

const Map = forwardRef<MapRef, MapProps>(function Map(
  {
    children,
    className,
    center = [-74.006, 40.7128],
    zoom = 12,
    mapTypeId = "roadmap",
    styles,
    disableDefaultUI = true,
  },
  ref
) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [mapInstance, setMapInstance] = useState<google.maps.Map | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  useImperativeHandle(ref, () => mapInstance as google.maps.Map, [mapInstance]);

  useEffect(() => {
    if (!containerRef.current) return;
    let cancelled = false;

    loadGoogleMaps().then(() => {
      if (cancelled || !containerRef.current) return;

      const map = new google.maps.Map(containerRef.current, {
        center: { lat: center[1], lng: center[0] },
        zoom,
        mapTypeId,
        styles: styles || [],
        disableDefaultUI: true,
        zoomControl: false,
        clickableIcons: false,
        gestureHandling: "greedy",
      });

      setMapInstance(map);

      google.maps.event.addListenerOnce(map, "tilesloaded", () => {
        if (!cancelled) setIsLoaded(true);
      });
    });

    return () => {
      cancelled = true;
      setIsLoaded(false);
      setMapInstance(null);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const contextValue = useMemo(
    () => ({ map: mapInstance, isLoaded }),
    [mapInstance, isLoaded]
  );

  return (
    <MapContext.Provider value={contextValue}>
      <div className={cn("relative w-full h-full", className)}>
        <div ref={containerRef} className="absolute inset-0 z-0" />
        {!isLoaded && <DefaultLoader />}
        {mapInstance && isLoaded && children}
      </div>
    </MapContext.Provider>
  );
});

interface HtmlOverlayInstance extends google.maps.OverlayView {
  position: google.maps.LatLng;
  container: HTMLDivElement;
  setPosition(position: google.maps.LatLng): void;
}

function createHtmlOverlay(position: google.maps.LatLng, container: HTMLDivElement): HtmlOverlayInstance {
  const overlay = new google.maps.OverlayView() as HtmlOverlayInstance;
  overlay.position = position;
  overlay.container = container;

  overlay.onAdd = function () {
    const pane = this.getPanes()?.overlayMouseTarget;
    if (pane) {
      pane.appendChild(this.container);
    }
  };

  overlay.draw = function () {
    const projection = this.getProjection();
    if (!projection) return;
    const pos = projection.fromLatLngToDivPixel(this.position);
    if (pos) {
      this.container.style.position = "absolute";
      this.container.style.left = `${pos.x}px`;
      this.container.style.top = `${pos.y}px`;
      this.container.style.transform = "translate(-50%, -50%)";
    }
  };

  overlay.onRemove = function () {
    try {
      if (this.container.parentNode) {
        this.container.parentNode.removeChild(this.container);
      }
    } catch (e) {
    }
  };

  overlay.setPosition = function (newPosition: google.maps.LatLng) {
    this.position = newPosition;
    this.draw();
  };

  return overlay;
}

type MarkerContextValue = {
  container: HTMLDivElement;
};

const MarkerContext = createContext<MarkerContextValue | null>(null);

type MapMarkerProps = {
  longitude: number;
  latitude: number;
  children: ReactNode;
  onClick?: (e: MouseEvent) => void;
  onMouseEnter?: (e: MouseEvent) => void;
  onMouseLeave?: (e: MouseEvent) => void;
};

function MapMarker({
  longitude,
  latitude,
  children,
  onClick,
  onMouseEnter,
  onMouseLeave,
}: MapMarkerProps) {
  const { map } = useMap();
  const overlayRef = useRef<HtmlOverlayInstance | null>(null);
  const [container] = useState(() => {
    const el = document.createElement("div");
    el.style.cursor = "pointer";
    return el;
  });

  const callbacksRef = useRef({ onClick, onMouseEnter, onMouseLeave });
  callbacksRef.current = { onClick, onMouseEnter, onMouseLeave };

  useEffect(() => {
    const handleClick = (e: MouseEvent) => callbacksRef.current.onClick?.(e);
    const handleMouseEnter = (e: MouseEvent) => callbacksRef.current.onMouseEnter?.(e);
    const handleMouseLeave = (e: MouseEvent) => callbacksRef.current.onMouseLeave?.(e);

    container.addEventListener("click", handleClick);
    container.addEventListener("mouseenter", handleMouseEnter);
    container.addEventListener("mouseleave", handleMouseLeave);

    return () => {
      container.removeEventListener("click", handleClick);
      container.removeEventListener("mouseenter", handleMouseEnter);
      container.removeEventListener("mouseleave", handleMouseLeave);
    };
  }, [container]);

  useEffect(() => {
    if (!map) return;

    const position = new google.maps.LatLng(latitude, longitude);
    const overlay = createHtmlOverlay(position, container);
    overlay.setMap(map);
    overlayRef.current = overlay;

    return () => {
      overlayRef.current = null;
      overlay.setMap(null);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [map, container]);

  useEffect(() => {
    if (overlayRef.current) {
      overlayRef.current.setPosition(new google.maps.LatLng(latitude, longitude));
    }
  }, [latitude, longitude]);

  return (
    <MarkerContext.Provider value={{ container }}>
      {children}
    </MarkerContext.Provider>
  );
}

function MarkerContent({
  children,
  className,
}: {
  children?: ReactNode;
  className?: string;
}) {
  const ctx = useContext(MarkerContext);
  if (!ctx?.container) return null;

  return createPortal(
    <div className={cn("cursor-pointer", className)}>
      {children || (
        <div className="w-3 h-3 rounded-full bg-blue-500 border-2 border-white shadow-md" />
      )}
    </div>,
    ctx.container
  );
}

export {
  Map,
  MapMarker,
  MarkerContent,
  useMap,
  type MapRef,
  type MapProps,
};

