import { NextRequest, NextResponse } from "next/server";

const REPLIT_SIDECAR_ENDPOINT = "http://127.0.0.1:1106";

async function signObjectURL(bucketName: string, objectName: string): Promise<string> {
  const response = await fetch(
    `${REPLIT_SIDECAR_ENDPOINT}/object-storage/signed-object-url`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        bucket_name: bucketName,
        object_name: objectName,
        method: "GET",
        expires_at: new Date(Date.now() + 3600 * 1000).toISOString(),
      }),
    }
  );
  if (!response.ok) throw new Error(`Sign failed: ${response.status}`);
  const { signed_url } = await response.json();
  return signed_url;
}

export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ path: string[] }> }
) {
  const { path } = await params;
  const objectPath = path.join("/");

  const publicDir = process.env.PUBLIC_OBJECT_SEARCH_PATHS?.split(",")[0]?.trim();
  if (!publicDir) {
    return NextResponse.json({ error: "Storage not configured" }, { status: 500 });
  }

  const fullPath = publicDir.startsWith("/") ? publicDir.slice(1) : publicDir;
  const parts = fullPath.split("/");
  const bucketName = parts[0];
  const objectName = [...parts.slice(1), objectPath].join("/");

  try {
    const signedUrl = await signObjectURL(bucketName, objectName);
    const imageRes = await fetch(signedUrl);
    if (!imageRes.ok) {
      return NextResponse.json({ error: "Not found" }, { status: 404 });
    }
    const buffer = await imageRes.arrayBuffer();
    return new NextResponse(buffer, {
      headers: {
        "Content-Type": imageRes.headers.get("content-type") || "application/octet-stream",
        "Cache-Control": "public, max-age=86400",
      },
    });
  } catch {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }
}

src/components/map/map-controls.tsx.content:
"use client";

import { useState, useCallback } from "react";
import { useMap } from "@/components/ui/map";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import { Plus, Minus, Navigation, Shrink } from "lucide-react";

interface MapControlsProps {
  places?: Array<{ place: { lat: number; lng: number } }>;
}

export function MapControls({ places }: MapControlsProps) {
  const { map } = useMap();
  const [locating, setLocating] = useState(false);

  const handleZoomIn = useCallback(() => {
    if (!map) return;
    map.setZoom((map.getZoom() || 12) + 1);
  }, [map]);

  const handleZoomOut = useCallback(() => {
    if (!map) return;
    map.setZoom((map.getZoom() || 12) - 1);
  }, [map]);

  const handleLocateMe = useCallback(() => {
    if (!map || locating) return;
    if (!("geolocation" in navigator)) return;
    setLocating(true);

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        map.panTo({ lat: latitude, lng: longitude });
        map.setZoom(12);
        setLocating(false);
      },
      () => {
        setLocating(false);
      },
      { enableHighAccuracy: true, timeout: 10000 }
    );
  }, [map, locating]);

  const handleFitAll = useCallback(() => {
    if (!map || !places || places.length === 0) return;

    if (places.length === 1) {
      map.panTo({ lat: places[0].place.lat, lng: places[0].place.lng });
      map.setZoom(14);
    } else {
      const bounds = new google.maps.LatLngBounds();
      places.forEach((sp) => {
        bounds.extend({ lat: sp.place.lat, lng: sp.place.lng });
      });
      map.fitBounds(bounds, { top: 60, right: 60, bottom: 220, left: 60 });
    }
  }, [map, places]);

  return (
    <div
      className="absolute bottom-24 md:bottom-6 right-3 z-20 flex flex-col gap-2"
      data-testid="map-controls"
    >
      <div className="flex flex-col bg-background/90 backdrop-blur-sm rounded-md border shadow-md">
        <Button
          variant="ghost"
          size="icon"
          onClick={handleZoomIn}
          aria-label="Zoom in"
          data-testid="button-zoom-in"
          className="rounded-b-none"
        >
          <Plus className="h-4 w-4" />
        </Button>
        <Separator className="mx-1.5 w-auto" />
        <Button
          variant="ghost"
          size="icon"
          onClick={handleZoomOut}
          aria-label="Zoom out"
          data-testid="button-zoom-out"
          className="rounded-t-none"
        >
          <Minus className="h-4 w-4" />
        </Button>
      </div>

      <Button
        variant="ghost"
        size="icon"
        onClick={handleLocateMe}
        disabled={locating}
        aria-label="Go to my location"
        data-testid="button-locate-me"
        className={cn(
          "bg-background/90 backdrop-blur-sm border shadow-md",
          locating && "text-primary animate-pulse"
        )}
      >
        <Navigation className="h-4 w-4" />
      </Button>

      {places && places.length > 0 && (
        <Button
          variant="ghost"
          size="icon"
          onClick={handleFitAll}
          aria-label="Fit all places in view"
          data-testid="button-fit-all"
          className="bg-background/90 backdrop-blur-sm border shadow-md"
        >
          <Shrink className="h-4 w-4" />
        </Button>
      )}
    </div>
  );
}
